import{_ as e,o as d,c as o,ag as i}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"helix_missions","description":"","frontmatter":{},"headers":[],"relativePath":"scripts/helix-missions.md","filePath":"scripts/helix-missions.md"}'),a={name:"scripts/helix-missions.md"};function s(n,t,r,c,l,h){return d(),o("div",null,[...t[0]||(t[0]=[i(`<h1 id="helix-missions" tabindex="-1">helix_missions <a class="header-anchor" href="#helix-missions" aria-label="Permalink to &quot;helix_missions&quot;">​</a></h1><p>Visual mission and quest system for FiveM with an in-game flow editor, branching objectives, rewards, rating tiers, and player progress tracking.</p><p><strong>Version:</strong> 0.1.0 | <strong>License:</strong> Commercial | <strong>Dependencies:</strong> <a href="./helix-lib.html">helix_lib</a>, <a href="https://github.com/overextended/oxmysql" target="_blank" rel="noreferrer">oxmysql</a></p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><ul><li><strong>In-Game Flow Editor</strong> -- Visual node-based mission editor with place, move, connect, and delete tools</li><li><strong>12 Objective Types</strong> -- go_to, collect, deliver, eliminate, escort, survive, interact, vehicle, stealth, custom, checkpoint, photograph</li><li><strong>Branching Objectives</strong> -- Missions with multiple paths, conditions, and outcomes</li><li><strong>Rating System</strong> -- Gold, silver, and bronze completion ratings based on time taken</li><li><strong>Reward System</strong> -- Money, items, XP, reputation, and custom rewards with per-rating bonuses</li><li><strong>Storylines</strong> -- Chain missions into multi-chapter storylines with player choices</li><li><strong>Player Progress</strong> -- Per-player mission state, cooldowns, completion history, and aggregate stats</li><li><strong>NPC Integration</strong> -- Works with helix_npc for mission-giving NPCs</li><li><strong>Group Missions</strong> -- Cooperative multi-player missions with min/max player counts</li><li><strong>Failure Conditions</strong> -- Death, time limit, distance, detection, NPC death, vehicle destroyed, or custom</li><li><strong>Blip Management</strong> -- Automatic map blips with per-objective-type sprites and colours</li><li><strong>Test Mode</strong> -- Test missions in-editor with skip, teleport, invincibility, and force-complete tools</li></ul><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li><a href="./helix-lib.html">helix_lib</a> (required)</li><li><a href="https://github.com/overextended/oxmysql" target="_blank" rel="noreferrer">oxmysql</a> (required for persistence)</li><li><a href="./helix-npc.html">helix_npc</a> (optional, for NPC-based mission givers)</li></ul><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><ol><li>Download the latest release from <a href="https://github.com/Helix-Scripts/helix-missions/releases" target="_blank" rel="noreferrer">GitHub</a></li><li>Place <code>helix_missions</code> in your resources folder</li><li>Add <code>ensure helix_missions</code> to your <code>server.cfg</code> (after <code>helix_lib</code> and <code>oxmysql</code>)</li><li>Configure <code>shared/config.lua</code> to your liking</li><li>Restart your server</li></ol><h2 id="directory-structure" tabindex="-1">Directory Structure <a class="header-anchor" href="#directory-structure" aria-label="Permalink to &quot;Directory Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>helix_missions/</span></span>
<span class="line"><span>+-- fxmanifest.lua</span></span>
<span class="line"><span>+-- client/</span></span>
<span class="line"><span>|   +-- main.lua                # Client bootstrap, NUI callbacks, keybinds</span></span>
<span class="line"><span>|   +-- ObjectiveRenderer.lua   # Blips, markers, and world rendering</span></span>
<span class="line"><span>|   +-- MissionHUD.lua          # Mission tracker overlay</span></span>
<span class="line"><span>|   +-- MissionRuntime.lua      # Client-side mission state machine</span></span>
<span class="line"><span>|   +-- EditorMode.lua          # In-game visual editor</span></span>
<span class="line"><span>|   +-- TestMode.lua            # Mission test/debug mode</span></span>
<span class="line"><span>+-- server/</span></span>
<span class="line"><span>|   +-- main.lua                # Server bootstrap, net events, admin events</span></span>
<span class="line"><span>|   +-- MissionManager.lua      # Mission CRUD, start/complete/fail logic</span></span>
<span class="line"><span>|   +-- ObjectiveManager.lua    # Objective validation and advancement</span></span>
<span class="line"><span>|   +-- PlayerProgress.lua      # Per-player state, saves, cooldowns, stats</span></span>
<span class="line"><span>+-- shared/</span></span>
<span class="line"><span>|   +-- config.lua              # All configuration</span></span>
<span class="line"><span>|   +-- types.lua               # EmmyLua type annotations</span></span>
<span class="line"><span>+-- nui/                        # React + Vite editor and HUD UI</span></span>
<span class="line"><span>+-- nui-dist/                   # Built NUI output</span></span></code></pre></div><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>All configuration lives in <code>shared/config.lua</code>.</p><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>Config.General.max_active_missions</code></td><td><code>number</code></td><td><code>3</code></td><td>Max missions a player can have active simultaneously</td></tr><tr><td><code>Config.General.auto_save_interval</code></td><td><code>number</code></td><td><code>60</code></td><td>Seconds between auto-saving player progress</td></tr><tr><td><code>Config.General.debug</code></td><td><code>boolean</code></td><td><code>false</code></td><td>Enable debug logging</td></tr><tr><td><code>Config.General.default_locale</code></td><td><code>string</code></td><td><code>&#39;en&#39;</code></td><td>Default language for mission text</td></tr><tr><td><code>Config.General.allow_replay</code></td><td><code>boolean</code></td><td><code>true</code></td><td>Whether players can replay completed missions</td></tr><tr><td><code>Config.General.default_replay_cooldown</code></td><td><code>number</code></td><td><code>3600</code></td><td>Seconds before a mission can be replayed</td></tr></tbody></table><h3 id="editor" tabindex="-1">Editor <a class="header-anchor" href="#editor" aria-label="Permalink to &quot;Editor&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>Config.Editor.max_objectives_per_mission</code></td><td><code>number</code></td><td><code>50</code></td><td>Maximum objectives per mission</td></tr><tr><td><code>Config.Editor.max_npcs</code></td><td><code>number</code></td><td><code>20</code></td><td>Maximum NPCs per mission</td></tr><tr><td><code>Config.Editor.max_props</code></td><td><code>number</code></td><td><code>30</code></td><td>Maximum props per mission</td></tr><tr><td><code>Config.Editor.max_triggers</code></td><td><code>number</code></td><td><code>20</code></td><td>Maximum triggers per mission</td></tr><tr><td><code>Config.Editor.max_rewards</code></td><td><code>number</code></td><td><code>10</code></td><td>Maximum rewards per mission</td></tr><tr><td><code>Config.Editor.max_failure_conditions</code></td><td><code>number</code></td><td><code>10</code></td><td>Maximum failure conditions per mission</td></tr><tr><td><code>Config.Editor.auto_save_interval</code></td><td><code>number</code></td><td><code>30</code></td><td>Editor auto-save interval (seconds)</td></tr><tr><td><code>Config.Editor.version_history</code></td><td><code>boolean</code></td><td><code>true</code></td><td>Enable mission version history</td></tr><tr><td><code>Config.Editor.max_versions</code></td><td><code>number</code></td><td><code>50</code></td><td>Maximum versions to keep</td></tr></tbody></table><h3 id="hud" tabindex="-1">HUD <a class="header-anchor" href="#hud" aria-label="Permalink to &quot;HUD&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>Config.HUD.position</code></td><td><code>string</code></td><td><code>&#39;top-right&#39;</code></td><td>Mission tracker position on screen</td></tr><tr><td><code>Config.HUD.default_expanded</code></td><td><code>boolean</code></td><td><code>true</code></td><td>Whether tracker starts expanded</td></tr><tr><td><code>Config.HUD.max_visible_objectives</code></td><td><code>number</code></td><td><code>5</code></td><td>Max objectives shown in tracker</td></tr><tr><td><code>Config.HUD.show_distance</code></td><td><code>boolean</code></td><td><code>true</code></td><td>Show distance to objective</td></tr><tr><td><code>Config.HUD.show_timer</code></td><td><code>boolean</code></td><td><code>true</code></td><td>Show time remaining for timed objectives</td></tr><tr><td><code>Config.HUD.notification_duration</code></td><td><code>number</code></td><td><code>5000</code></td><td>Notification duration in ms</td></tr></tbody></table><h3 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>Config.Performance.objective_check_interval</code></td><td><code>number</code></td><td><code>500</code></td><td>Milliseconds between objective condition checks</td></tr><tr><td><code>Config.Performance.entity_lod_distance</code></td><td><code>number</code></td><td><code>100.0</code></td><td>Distance at which entities LOD/despawn</td></tr><tr><td><code>Config.Performance.max_concurrent_missions</code></td><td><code>number</code></td><td><code>20</code></td><td>Max concurrent missions across all players</td></tr><tr><td><code>Config.Performance.blip_render_distance</code></td><td><code>number</code></td><td><code>500.0</code></td><td>Distance at which blips become visible</td></tr><tr><td><code>Config.Performance.max_entities_per_mission</code></td><td><code>number</code></td><td><code>50</code></td><td>Max spawned entities per mission</td></tr><tr><td><code>Config.Performance.server_tick_rate</code></td><td><code>number</code></td><td><code>1000</code></td><td>Server-side mission processing interval (ms)</td></tr></tbody></table><h3 id="integration" tabindex="-1">Integration <a class="header-anchor" href="#integration" aria-label="Permalink to &quot;Integration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>Config.Integration.use_helix_npc</code></td><td><code>boolean</code></td><td><code>true</code></td><td>Use helix_npc for mission NPCs</td></tr><tr><td><code>Config.Integration.use_helix_economy</code></td><td><code>boolean</code></td><td><code>true</code></td><td>Use helix_economy for rewards/costs</td></tr><tr><td><code>Config.Integration.use_helix_crafting</code></td><td><code>boolean</code></td><td><code>true</code></td><td>Use helix_crafting for item requirements</td></tr><tr><td><code>Config.Integration.use_helix_dispatch</code></td><td><code>boolean</code></td><td><code>true</code></td><td>Use helix_dispatch for dispatch integration</td></tr></tbody></table><h3 id="rewards" tabindex="-1">Rewards <a class="header-anchor" href="#rewards" aria-label="Permalink to &quot;Rewards&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>Config.Rewards.default_currency</code></td><td><code>string</code></td><td><code>&#39;cash&#39;</code></td><td>Default currency type for money rewards</td></tr><tr><td><code>Config.Rewards.max_cash_reward</code></td><td><code>number</code></td><td><code>100000</code></td><td>Maximum cash reward per mission</td></tr><tr><td><code>Config.Rewards.xp_multiplier</code></td><td><code>number</code></td><td><code>1.0</code></td><td>XP multiplier for all rewards</td></tr><tr><td><code>Config.Rewards.first_completion_bonus</code></td><td><code>number</code></td><td><code>1.5</code></td><td>Bonus multiplier for first completion</td></tr><tr><td><code>Config.Rewards.rating_thresholds.gold</code></td><td><code>number</code></td><td><code>0.75</code></td><td>Complete in under 75% of estimated time for gold</td></tr><tr><td><code>Config.Rewards.rating_thresholds.silver</code></td><td><code>number</code></td><td><code>1.0</code></td><td>Complete within estimated time for silver</td></tr><tr><td><code>Config.Rewards.rating_thresholds.bronze</code></td><td><code>number</code></td><td><code>1.5</code></td><td>Complete within 150% of estimated time for bronze</td></tr></tbody></table><h2 id="objective-types" tabindex="-1">Objective Types <a class="header-anchor" href="#objective-types" aria-label="Permalink to &quot;Objective Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>go_to</code></td><td>Navigate to a location</td></tr><tr><td><code>collect</code></td><td>Collect items from the world</td></tr><tr><td><code>deliver</code></td><td>Deliver items to a location or NPC</td></tr><tr><td><code>eliminate</code></td><td>Eliminate targets</td></tr><tr><td><code>escort</code></td><td>Escort an NPC to a destination</td></tr><tr><td><code>survive</code></td><td>Survive for a duration</td></tr><tr><td><code>interact</code></td><td>Interact with an object or NPC</td></tr><tr><td><code>vehicle</code></td><td>Vehicle-based objective (drive to, deliver vehicle)</td></tr><tr><td><code>stealth</code></td><td>Complete without being detected</td></tr><tr><td><code>custom</code></td><td>Custom objective via export/callback</td></tr><tr><td><code>checkpoint</code></td><td>Pass through checkpoints in order</td></tr><tr><td><code>photograph</code></td><td>Photograph a target</td></tr></tbody></table><h2 id="keybinds" tabindex="-1">Keybinds <a class="header-anchor" href="#keybinds" aria-label="Permalink to &quot;Keybinds&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Toggle Tracker</td><td><code>M</code></td><td>Show or hide the mission tracker</td></tr><tr><td>Open Journal</td><td><code>J</code></td><td>Open the mission journal</td></tr><tr><td>Interact</td><td><code>E</code></td><td>Interact with mission elements</td></tr><tr><td>Toggle Editor</td><td><code>F10</code></td><td>Open or close the mission editor (requires permission)</td></tr></tbody></table><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Permission</th><th>Description</th></tr></thead><tbody><tr><td><code>helix.missions.editor</code></td><td>Access to the in-game mission editor</td></tr><tr><td><code>helix.missions.admin</code></td><td>Access to admin commands (publish, archive, force-complete, server stats)</td></tr></tbody></table><h2 id="communication" tabindex="-1">Communication <a class="header-anchor" href="#communication" aria-label="Permalink to &quot;Communication&quot;">​</a></h2><p>helix_missions uses network events rather than traditional exports. All client-server communication flows through <code>RegisterNetEvent</code> handlers and NUI callbacks.</p><h3 id="integration-events" tabindex="-1">Integration Events <a class="header-anchor" href="#integration-events" aria-label="Permalink to &quot;Integration Events&quot;">​</a></h3><p>Other scripts can listen for mission lifecycle events:</p><div class="language-lua vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">lua</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- Server-side: listen for mission completion</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">AddEventHandler</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;helix_missions:missionCompleted&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(source, missionId, rating)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">((</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Player %d completed mission %s with %s rating&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">):</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">format</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(source, missionId, rating))</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">end</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div>`,36)])])}const u=e(a,[["render",s]]);export{m as __pageData,u as default};
